2	  light: "pierre-light",
3	  dark: "pierre-dark",
4	} as const;
5	
6	export type DiffThemeName = (typeof DIFF_THEME_NAMES)[keyof typeof DIFF_THEME_NAMES];
7	
8	export function resolveDiffThemeName(theme: "light" | "dark"): DiffThemeName {
9	  return theme === "dark" ? DIFF_THEME_NAMES.dark : DIFF_THEME_NAMES.light;
