import { useTheme } from "~/contexts/ThemeContext";
import type { Theme } from "@t3tools/shared/themes";

function ThemeSwatch({ theme, selected }: { theme: Theme; selected: boolean }) {
  const { setTheme } = useTheme();

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={`Select ${theme.name} theme`}
      className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={() => setTheme(theme.id)}
    >
      {/* Color swatch preview */}
      <span
        aria-hidden="true"
        className="flex shrink-0 overflow-hidden rounded-md border border-black/10"
        style={{ width: 40, height: 28 }}
      >
        {/* Background block */}
        <span
          className="flex h-full flex-1 flex-col"
          style={{ background: theme.colors.background }}
        >
          {/* Sidebar strip */}
          <span
            className="block h-full"
            style={{ width: 10, background: theme.colors.sidebar, flexShrink: 0 }}
          />
        </span>
        {/* Accent strip at the bottom */}
        <span
          className="absolute"
          style={{
            // Render as a small accent bar inside the swatch
            display: "block",
          }}
        />
      </span>

      {/* Better swatch: sidebar | editor split with accent bar */}
      <SwatchPreview theme={theme} />

      <span className="flex min-w-0 flex-1 flex-col">
        <span className="text-sm font-medium leading-tight">{theme.name}</span>
        <span className="mt-0.5 font-mono text-[10px] opacity-50">{theme.id}</span>
      </span>

      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

/** Compact visual preview showing sidebar / editor / accent colours. */
function SwatchPreview({ theme }: { theme: Theme }) {
  return (
    <span
      aria-hidden="true"
      className="relative shrink-0 overflow-hidden rounded border border-black/10"
      style={{ width: 44, height: 30 }}
    >
      {/* Sidebar column */}
      <span
        className="absolute inset-y-0 left-0"
        style={{ width: 12, background: theme.colors.sidebar }}
      />
      {/* Editor area */}
      <span
        className="absolute inset-y-0"
        style={{ left: 12, right: 0, background: theme.colors.editor }}
      />
      {/* Accent status bar strip at the bottom */}
      <span
        className="absolute inset-x-0 bottom-0"
        style={{ height: 4, background: theme.colors.statusBar }}
      />
      {/* Foreground text simulation lines */}
      <span
        className="absolute"
        style={{
          top: 6,
          left: 16,
          right: 4,
          height: 2,
          borderRadius: 1,
          background: theme.colors.foreground,
          opacity: 0.35,
        }}
      />
      <span
        className="absolute"
        style={{
          top: 12,
          left: 16,
          right: 10,
          height: 2,
          borderRadius: 1,
          background: theme.colors.foreground,
          opacity: 0.2,
        }}
      />
      {/* Accent dot (simulates a highlighted token) */}
      <span
        className="absolute"
        style={{
          top: 6,
          left: 16,
          width: 18,
          height: 2,
          borderRadius: 1,
          background: theme.colors.accent,
          opacity: 0.8,
        }}
      />
    </span>
  );
}

/**
 * A radio-group style theme selector that lists every available theme with a
 * colour-swatch preview. Drop this into any settings surface.
 */
export function ThemeSelector() {
  const { theme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Visual theme">
      {availableThemes.map((t) => (
        <ThemeSwatch key={t.id} theme={t} selected={theme.id === t.id} />
      ))}
    </div>
  );
}

