/** Color palette for a visual theme. All values are CSS color strings. */
export interface ThemeColors {
  /** Main application background */
  background: string;
  /** Primary text / foreground color */
  foreground: string;
  /** Interactive accent color (buttons, highlights, rings) */
  accent: string;
  /** Sidebar / navigation panel background */
  sidebar: string;
  /** Code editor pane background */
  editor: string;
  /** Integrated terminal background */
  terminal: string;
  /** Status bar background */
  statusBar: string;
}

/** A complete visual theme definition. */
export interface Theme {
  /** Unique stable identifier, e.g. "t3-dark" */
  id: string;
  /** Human-readable display name */
  name: string;
  /** Color palette */
  colors: ThemeColors;
  /** CSS font-family value applied to the editor / UI */
  fontFamily: string;
  /** Base font size in pixels */
  fontSize: number;
}

const BUILT_IN_THEMES: ReadonlyArray<Theme> = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0f0f11",
      foreground: "#e4e4e7",
      accent: "#7c3aed",
      sidebar: "#09090b",
      editor: "#0f0f11",
      terminal: "#09090b",
      statusBar: "#7c3aed",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#18181b",
      accent: "#7c3aed",
      sidebar: "#f4f4f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#7c3aed",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#040408",
      foreground: "#c8c8d8",
      accent: "#6366f1",
      sidebar: "#020206",
      editor: "#040408",
      terminal: "#020206",
      statusBar: "#4f46e5",
    },
    fontFamily: '"DM Sans", system-ui, sans-serif',
    fontSize: 14,
  },
] as const;

const DEFAULT_THEME_ID = "t3-dark";

/**
 * Returns all available built-in themes.
 */
export function listThemes(): ReadonlyArray<Theme> {
  return BUILT_IN_THEMES;
}

/**
 * Looks up a theme by id. Falls back to the default theme ("t3-dark") if
 * the id is not recognised.
 */
export function getTheme(id: string): Theme {
  const found = BUILT_IN_THEMES.find((theme) => theme.id === id);
  if (found !== undefined) return found;
  // Safe non-null: DEFAULT_THEME_ID is always present in BUILT_IN_THEMES.
  return BUILT_IN_THEMES.find((t) => t.id === DEFAULT_THEME_ID) as Theme;
}

