import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Storage
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:custom-theme";

// ---------------------------------------------------------------------------
// Module-level external store (mirrors the pattern used by useColorScheme)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let cachedTheme: Theme | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): string {
  return localStorage.getItem(STORAGE_KEY) ?? "t3-dark";
}

function resolveTheme(): Theme {
  const id = getStoredThemeId();
  if (cachedTheme !== null && cachedTheme.id === id) return cachedTheme;
  cachedTheme = getTheme(id);
  return cachedTheme;
}

function applyThemeToDom(theme: Theme): void {
  const root = document.documentElement;
  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);
}

// Apply immediately on module load to prevent flash.
applyThemeToDom(resolveTheme());

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme changes made in other tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key !== STORAGE_KEY) return;
    cachedTheme = null;
    applyThemeToDom(resolveTheme());
    emitChange();
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

function getSnapshot(): Theme {
  return resolveTheme();
}

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

interface ThemeContextValue {
  theme: Theme;
  setTheme: (id: string) => void;
  availableThemes: ReadonlyArray<Theme>;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

export function ThemeProvider({ children }: { children: ReactNode }) {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: string) => {
    localStorage.setItem(STORAGE_KEY, id);
    cachedTheme = null;
    applyThemeToDom(getTheme(id));
    emitChange();
  }, []);

  const availableThemes = listThemes();

  // Keep the DOM in sync whenever the resolved theme changes (e.g. after SSR
  // hydration or a storage event from another tab).
  useEffect(() => {
    applyThemeToDom(theme);
  }, [theme]);

  const contextValue = useMemo(
    () => ({ theme, setTheme, availableThemes }),
    [theme, setTheme, availableThemes],
  );

  return <ThemeContext value={contextValue}>{children}</ThemeContext>;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Returns the current custom visual theme and helpers for changing it.
 *
 * Must be called inside a `<ThemeProvider>`.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (ctx === null) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return ctx;
}
